#[inline]
fn reverse_segment(state: &mut LuaState, from: StackIdx, to: StackIdx) {
    // C: for (; from < to; from++, to--) { TValue temp; setobj...; setobjs2s...; setobj2s...; }
    let mut lo = from.0;
    let mut hi = to.0;
