    //      tm = luaT_gettmbyobj(L, p2, event);  /* try second operand */
    let tm = if tm.is_nil() {
        get_tm_by_obj(state, p2, event)
    } else {
        tm
    };
    // C: if (notm(tm)) return 0;
    if tm.is_nil() {
        return Ok(false);
